mapper.update:
UPDATE person_daily_attendance
SET attendance_status = CAST(#{attendanceStatus} AS attendance_status),
    current_session_id = #{sessionId},
    updated_at = NOW()
WHERE stat_date = #{statDate}
  AND person_id = #{personId}

mapper.select:
SELECT pda.id, pda.stat_date::text AS statDate, pda.person_id AS personId, p.display_name AS displayName, p.employee_no AS employeeNo, p.person_type::text AS personType, pda.camera_id AS cameraId, c.device_name AS deviceName, pda.first_enter_at AS firstEnterAt, pda.last_exit_at AS lastExitAt, pda.total_dwell_seconds AS totalDwellSeconds, pda.enter_count AS enterCount, pda.attendance_status::text AS attendanceStatus, pda.is_attended AS isAttended, pda.current_session_id AS currentSessionId FROM person_daily_attendance pda INNER JOIN persons p ON p.id = pda.person_id LEFT JOIN camera c ON c.id = pda.camera_id
pda.stat_date >= #{beginDate} AND pda.stat_date <= #{endDate}
AND pda.camera_id = #{cameraId}
AND p.person_type::text = #{personType}
AND p.person_type::text IN ('student', 'staff')
AND p.display_name ILIKE CONCAT('%', #{displayName}, '%')
AND p.employee_no = #{employeeNo}
AND pda.attendance_status::text = #{attendanceStatus}
ORDER BY pda.first_enter_at DESC NULLS LAST, pda.id DESC LIMIT #{limit}
